const Q_GEOGRAPHY_2020_MODEL_I=[{"id": "objective>Geography>2020 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Loss of farmland can be contributed to all the following except?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sedimentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Leaching</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desertification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sheet erosion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentation, in the geological sciences, process of deposition of a solid material from a  <br/> state of suspension or solution in a fluid (usually air or water). <br/> Leaching is the wearing away of the top Nutrient of a soil by erosion or irrigation. <br/> Desertification is the process of desert formation through the act of tree cutting without replacement. <br/> Over grazing occurs when livestock feed repeated on a piece of land without replanting . <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2020 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term gauge in railway transport refers to the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">weight of vehicles that the gauge can bear</div>", "<div style=\"font-family:Cambria;font-size:17px;\">measurement of gradient along the side slopes of the rails.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Length of rails in a country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Distance between rails of a track</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In rail transport,track gauge or track gage is the spacing of the rails on a rail way track and is measured between the inner races of the road bearing rails</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2020 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors must account for the rapid increase of the world population during the 20th century? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Slave trade was abolished</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Death rate decreased rapidly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Birth rate has increased rapidly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increasing world population of food</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">With the advancement of technology and health care system,these factors has contributed to the decrease in death rate.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2020 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population of a certain country was observed to be 46 million males and 41 million females within a land area of about 175,000km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. What is the average density of the population.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">503 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">551 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\"> 2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">266 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\"> 2</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">237 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\"> 2</span> <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population density=Total population∻ Total land area <br/> Total population=(41+46)million=87 million <br/> Population density=87 million∻175,000=502.89=503 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2020 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rise in the population of an area can be measured easily by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Multiplying the natural increase by the net migration.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Substracting the natural increase from the net migration.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adding the natural increase to the net migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dividing the natural increase by the net migration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Increase in population can be calculated by adding the natural increase by the net migration(no of birth) to the net migration.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2020 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The areas in Nigeria where temperate crops may be grown includes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Jos plateau and Mambula plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mandara mountain and Biu plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Apata hills and Efong ridges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Obah hills and Yoruba highlands</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, temperate crops can be grown in areas with a cooler climate, such as high-altitude regions. The Jos plateau and Mambula plateau are such regions in Nigeria where the climate is cooler due to the high altitude, making them suitable for the growth of temperate crops.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2020 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main hydrological centre in Nigeria is the? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Jos plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western uplands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biu plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eastern ruglands</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jos plateau is an hydrological centre because of its cold temperature. At an altitude of 1,217m (3,993 ft) above sea level Jos climate is closer to temperate than that of the vast majority of Nigeria.Average monthly temperatures range from 21-23<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C (70-77<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>F) and from mid november to late January,night time temperature drops as low as 7<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C (45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>F)</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2020 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most urbanised part of Nigeria is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">South-East</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Middle-belt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North-East</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South-West</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most urbanised part of Nigeria is the South-West. This is due to the presence of major cities like Lagos, Ibadan, and Abeokuta which are highly urbanised.</div>", "topic": "REGIONAL GEOGRAPHY : POPULATION DISTRIBUTION IN WEST AFRICA"}, {"id": "objective>Geography>2020 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest hydro-electric power potential is found?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sokoto-Rima Basin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cross-river Basin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger-benue trough</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Enugu scarp lands</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Niger state is the base of kanji dam the largest in Nigeria, it is where hydro-electric power is generated in Nigeria</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2020 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following features is of volcanic origin?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zeugen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Loess</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gorge</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sill is a tabular sheet intrusion that has intruded between older layers of sedimentary rocks, beds or volcanic lava or tuffs or along the direction of rotation of metamorphic rock.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2020 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The core of the earth is also called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mesosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lithosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Barysphere</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The barysphere is the innermost core of the earth's crust, the hydrosphere is the portion of the earth  covered by water, it occupies 70% of the earth's crust.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2020 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which rock involves stratification?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Metamorphic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Volcanic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Igneous</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stratification or stratum, the layering of rocks, stratification (archeology), the formation of layers(strata) in which objects are found. <br/> Stratification, the layering that occurs in most sedimentary rocks and in those igneous rocks formed at the Earth's surface, as from lava flows and volcanic fragmental deposits. The layers range from several millimetres to many metres in thickness and vary greatly in shape.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2020 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The point where R.Isbo meets R.Gembeh is called <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An entrepot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A watershed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A lagoon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A confluence</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Where two Rivers meet is called a confluence <br/> Lagoon is a shallow body of water separated from deeper sea by a bar.\t <br/> </div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2020 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/>Using the Map above  <br/> The contour interval on the map is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50 metres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100metres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150 metres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200 metres</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the map <br/> Contour interval is  the difference in elevation represented by each contour line on a topographic map . <br/> </div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2020 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major useful component of the atmosphere is ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Neon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbondioxide </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen is the major useful component of the atmosphere because it is essential for the survival of most life forms on earth as it is used for respiration.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2020 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The atmospheric condition of a place over a long period of time refers to it's ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Weather </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Climate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Weather is the atmospheric condition of a place over a long period of time.While Climate is the long-term average of weather, typically averaged over a period of 30 years. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2020 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The largest deposit of gold in West Africa is found in ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ghana </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liberia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Seria leone</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is why Ghana was formerly called gold coast.Ghana's gold output of 4.8 million ounces in 2018 surpassed South Africa's 4.2 million ounce total for the first time and being one of the largest producer in Africa and the world . <br/> </div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2020 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In most of West Africa countries the primary purpose of establishing the rail system was to ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transport export goods to the coast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Distribute locally produced commodities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provide cheap means of moving passengers\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Supplement river transport</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Major reason is to transport export goods to the coast areas where there is seaport to export .For example the train line from Kano to Lagos ,Lagos has over 4 sea ports. <br/> </div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>2020 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The port that specializes in receiving and re-exporting goods is known as  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">seaport</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jetty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Entrepot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">International port</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entrepot is a port city or other center to which goods are brought for import and export and for collection and distribution <br/> </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2020 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The middle course of a river normally shows </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Levee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Meanders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ox-bow lakes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A meander is a bend in a river channel. Meanders form when water in the river erodes the banks on the outside of the channel. The water deposits sediment on the inside of the channel. Meanders only occur on flat land where the river is large and established. <br/> </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2020 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The development of a climax vegetation in the Savannah belt of Nigeria is disturbed mainly by ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lumbering </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bush burning </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Animal grazing </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Animal grazing mostly by cattles and goats ,rearng of this livestock is a common pratices inThis area such as Kastina ,Adamawa in Nigeria  <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2020 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the soil types is the most permeable ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Loamy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Laterite</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Permeability in soil science refers to the ability of the soil to allow water to pass through it. Sand has the highest permeability among the given options. This is because sand particles are larger and have bigger spaces (pores) between them, allowing water to pass through more easily compared to loamy, clay, and laterite soils.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2020 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following Africa country does not export petroleum?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Libya</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kenya</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Botswana</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kenya majorly export ore,tin and some rare natural minerals. <br/> </div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2020 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Weathering ,Erosion, transportation and deposition and processes of ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mass wasting </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Volcanicity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Denudation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Exforliation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Denudation is the laying bare of rocks by the washing away of the overlying earth, etc.; or the  <br/> excavation and removal of them by the action of running water. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2020 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The interaction of a community of organisms with its abiotic environment constitutes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">niche</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a food chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an ecosystem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a microhabitat</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">: Ecosystem is the interaction of organisms (plants, animals, microbes) with each other and their environment</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2020 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Coal and Mineral oil are usually found embedded in  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Crystallime rocks </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Igneous rocks </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metamorphic rocks </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentary rocks </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentary rocks are types of rock that are formed by the accumulation or deposition of small particles and subsequent cementation of mineral or organic particles on the floor of oceans or other bodies of water at the Earth's surface.The particles that form a sedimentary rock are called sediment, and may be composed of geological detritus (minerals such as oil,coal ,quartz) or biological detritus (organic matter). <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2020 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water pollution is caused by all the following except? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increased silt load</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sand filling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sewage disposal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial effluent</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Explanation:Sand Filling is the rehandling method involves transporting sand by barges and dumping the fill material temporarily in the pit for storage.The procedure is carried out on land and does not affect water  <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2020 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The satellite of the Earth is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The sun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jupiter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Moon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saturn</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Moon is an astronomical body orbiting Earth as its only natural satellite. It is the fifth- <br/> largest satellite in the Solar System, and by far the largest among planetary satellites relative to the size of <br/>  the planet that it orbits (its primary). <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2020 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lines of the Longitude can best be described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Parallel lines that shows the angular distance of a place north or south of the equator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Imaginary lines on the Earth's surface running from the north pole to the South Pole and at right angles to the parallels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Semi-circles on the globes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The distance of a place east or west of the prime meridian</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lines of longitude are  imaginary great circle on the surface of the earth passing through the north and south poles at right angles to the equator\t <br/>  <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2020 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The feature formed by cooling of molten magma across the bedding plane is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dyke</div>", "<div style=\"font-family:Cambria;font-size:17px;\">batholith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Laccolith</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sills are the intrusive igneous rocks which are formed by the solidified and near horizontal lava layers inside the earth. The thinner deposits of these rocks are called sheets, while the thicker horizontal deposits are known as sills. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2020 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following does not encourage desertification?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Large scale irrigation schemes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduction in mean annual rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Overgrazing and over cultivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bush Burning </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">irrigation is the process of supplying farmland with water, by building ditches, pipes ,thereby increasing plant/crops growth .While desertification is the process by which a geographic region becomes a desert. The change may result from natural changes in climate or by human activity. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2020 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sparsed population of the middle belt of weat Africa could be traced to all the following factors except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Inter-Ethnic wars</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Arab slave trade in the North</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Swamps created by River Niger and Venue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">European slave trade in the south </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">European slaves by British and France in the west Africa during the early 1900's migrated many of the population in the south to European,American and some parts of Africa like Liberia . <br/> </div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2020 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nucleated groups of houses occupied largely by people engaged in primary occupation are referred to as? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Metropolises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Villages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Farmstead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Towns</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A village is a small settlement usually found in a rural setting. It is generally larger than a \"hamlet\" but smaller than a \"town\". Some geographers specifically define a village as having between 500 and 2,500 inhabitants. In most parts of the world, villages are settlements of people clustered around a  <br/> central point <br/> </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2020 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In which part of the mapped area is lumbering a likely economic activity? <br/>  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Northeast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Southeast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Southwest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Northwest</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lumbering is the act of felling trees or timber in the forest .This activity can only be carried out in the forest .From the map forest only exist in the North East ,therefore Lumbering activities can only occur in the Northeast <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2020 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which is simplest method of rapid distance measurement in surveying? <br/>  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tape measurement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Compass measurement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pacing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chaining</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pacing is a reasonably easy and quick method of measuring distance in the field. It is used to measure a distance and is often used with a sighting or a hand compass. Most commonly, pacing is split up into segments, such as chains, which are set measures of distance. <br/> </div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2020 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following types of bar graphs shows increases and decreases compared with a given average ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Divided bar graph</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Group Bar graph</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Divergent bar graph</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Percentage bar graph</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A divided bar graph is a rectangle divided into smaller rectangles along its length in proportion to the data. Segments in a divided bar represent a set of quantities according to the different proportion of the total amount. A divided bar diagram is created using rectangular bars to depict proportionally the size of each category. The bars in a divided bar graph can be vertical or horizontal.  <br/> </div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2020 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industries like cement manufacturing and iron and steel are usually located close to the site of raw materials because? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">finished products are delicate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials are abundant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials also occur at market site</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total transport costs are reduced</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factors to considered while establishing industries is nearness to raw material because it reduces cost of transport and production and makes raw material readily available . <br/> </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2020 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Factors to considered while establishing industries is nearness to raw material because it reduces cost of transport and production and makes raw material readily available . <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are evenly spread over major towns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">produce mainly for domestic market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are capital intensive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have wide markets for their products</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is due to lack of capital for large scale production,low quality and reduces cost of production,making these manufacturer produce only for domestic markets. <br/> </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2020 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The world's leading producer of cocoa is ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ecuador</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brazil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Ivory Coast and Ghana are by far the two largest producers of cocoa: together they cultivate more than half of the world´s cocoa. These two are followed by other cocoa producing countries like Indonesia, Nigeria, Cameroon, Brazil and Ecuador. <br/> </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2020 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On a population map of the world all but one of the following appears generally as region of low population density? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hot desert <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amazon forest <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Antartica <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Island of Java <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Antartica has no permanent residents,and contains research stations and field camps that are staffed seasonally or year-round, and former whaning setllement.The largest station Mc-Murdo stations has a summer population of about 1000 people and a winter population of about 200. <br/> </div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}];
